(() => {
  "use strict";

  const encoder = new TextEncoder();
  const crcTable = new Uint32Array(256);

  for (let i = 0; i < 256; i += 1) {
    let value = i;
    for (let bit = 0; bit < 8; bit += 1) {
      value = value & 1 ? 0xedb88320 ^ (value >>> 1) : value >>> 1;
    }
    crcTable[i] = value >>> 0;
  }

  function crc32(bytes) {
    let crc = 0xffffffff;
    for (const byte of bytes) {
      crc = crcTable[(crc ^ byte) & 0xff] ^ (crc >>> 8);
    }
    return (crc ^ 0xffffffff) >>> 0;
  }

  function pushUint16(bytes, value) {
    bytes.push(value & 0xff, (value >>> 8) & 0xff);
  }

  function pushUint32(bytes, value) {
    bytes.push(value & 0xff, (value >>> 8) & 0xff, (value >>> 16) & 0xff, (value >>> 24) & 0xff);
  }

  function dosDateTime(date) {
    const year = Math.max(1980, date.getFullYear());
    const dosTime = (date.getHours() << 11) | (date.getMinutes() << 5) | Math.floor(date.getSeconds() / 2);
    const dosDate = ((year - 1980) << 9) | ((date.getMonth() + 1) << 5) | date.getDate();
    return { dosDate, dosTime };
  }

  function concat(chunks, length) {
    const output = new Uint8Array(length);
    let offset = 0;
    for (const chunk of chunks) {
      output.set(chunk, offset);
      offset += chunk.length;
    }
    return output;
  }

  class JSZip {
    constructor() {
      this.entries = [];
    }

    file(name, content) {
      const safeName = String(name || "file.md").replace(/^\/+/, "");
      const text = typeof content === "string" ? content : String(content || "");
      this.entries.push({
        name: safeName,
        content: encoder.encode(text),
        modified: new Date()
      });
      return this;
    }

    async generateAsync(options = {}) {
      const localParts = [];
      const centralParts = [];
      let offset = 0;
      let centralLength = 0;

      for (const entry of this.entries) {
        const nameBytes = encoder.encode(entry.name);
        const checksum = crc32(entry.content);
        const { dosDate, dosTime } = dosDateTime(entry.modified);
        const local = [];

        pushUint32(local, 0x04034b50);
        pushUint16(local, 20);
        pushUint16(local, 0x0800);
        pushUint16(local, 0);
        pushUint16(local, dosTime);
        pushUint16(local, dosDate);
        pushUint32(local, checksum);
        pushUint32(local, entry.content.length);
        pushUint32(local, entry.content.length);
        pushUint16(local, nameBytes.length);
        pushUint16(local, 0);

        const localHeader = concat([new Uint8Array(local), nameBytes, entry.content], local.length + nameBytes.length + entry.content.length);
        localParts.push(localHeader);

        const central = [];
        pushUint32(central, 0x02014b50);
        pushUint16(central, 20);
        pushUint16(central, 20);
        pushUint16(central, 0x0800);
        pushUint16(central, 0);
        pushUint16(central, dosTime);
        pushUint16(central, dosDate);
        pushUint32(central, checksum);
        pushUint32(central, entry.content.length);
        pushUint32(central, entry.content.length);
        pushUint16(central, nameBytes.length);
        pushUint16(central, 0);
        pushUint16(central, 0);
        pushUint16(central, 0);
        pushUint16(central, 0);
        pushUint32(central, 0);
        pushUint32(central, offset);

        const centralHeader = concat([new Uint8Array(central), nameBytes], central.length + nameBytes.length);
        centralParts.push(centralHeader);
        centralLength += centralHeader.length;
        offset += localHeader.length;
      }

      const end = [];
      pushUint32(end, 0x06054b50);
      pushUint16(end, 0);
      pushUint16(end, 0);
      pushUint16(end, this.entries.length);
      pushUint16(end, this.entries.length);
      pushUint32(end, centralLength);
      pushUint32(end, offset);
      pushUint16(end, 0);

      const bytes = concat([...localParts, ...centralParts, new Uint8Array(end)], offset + centralLength + end.length);
      if (options.type === "uint8array") {
        return bytes;
      }
      return new Blob([bytes], { type: "application/zip" });
    }
  }

  window.JSZip = JSZip;
})();
